using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool instances ---
var searchTool = new WebSearchTool();
var notesTool = new NoteTakingTool();

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. Your goal is to thoroughly research a topic
        the user provides by searching the web and taking notes on key findings.

        Follow this workflow:
        1. Break the topic into 2-3 focused search queries.
        2. For each query, call the web_search tool.
        3. After each search, call save_note to record the most important facts,
           data points, and source URLs.
        4. After all searches, call get_notes to review everything you collected.
        5. Produce a well-structured summary with sections, key findings, and sources.

        Always cite your sources. Be factual and concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools:
    [
        AIFunctionFactory.Create(searchTool.SearchAsync, nameof(WebSearchTool.SearchAsync)),
        AIFunctionFactory.Create(notesTool.SaveNote, nameof(NoteTakingTool.SaveNote)),
        AIFunctionFactory.Create(notesTool.GetNotes, nameof(NoteTakingTool.GetNotes)),
    ]);

// --- Main loop ---
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent (MAF)           ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic))
        continue;

    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notesTool.Clear();

    Console.WriteLine();
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine("(The agent will search the web and take notes — this may take a moment…)");
    Console.WriteLine();

    try
    {
        var session = await agent.CreateSessionAsync();
        var response = await agent.RunAsync($"Research this topic: {topic}", session);

        Console.WriteLine("── Research Summary ──────────────────────");
        Console.WriteLine(response.Text);
        Console.WriteLine("──────────────────────────────────────────");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }

    Console.WriteLine();
}

// ─── Tool Definitions ──────────────────────────────────────────

/// <summary>
/// Searches the web using DuckDuckGo HTML and extracts text snippets.
/// </summary>
sealed class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    static WebSearchTool()
    {
        s_http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    }

    [Description("Search the web for information on a given query. Returns text snippets from search results.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        try
        {
            var html = await s_http.GetStringAsync(url);

            // Extract result snippets from DuckDuckGo HTML results
            var snippets = ExtractSnippets(html);

            return snippets.Count > 0
                ? string.Join("\n\n", snippets.Select((s, i) => $"[{i + 1}] {s}"))
                : "No results found for this query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<string> ExtractSnippets(string html)
    {
        var snippets = new List<string>();

        // Extract snippet text from DuckDuckGo result divs
        var snippetMatches = Regex.Matches(
            html,
            @"class=""result__snippet""[^>]*>(.*?)</",
            RegexOptions.Singleline);

        foreach (Match match in snippetMatches)
        {
            var text = StripHtml(match.Groups[1].Value).Trim();
